def _coerce_quantity(value: object | None) -> int:
    if value in (None, ""):
        return 1
    try:
        quantity = int(str(value).strip())
    except (TypeError, ValueError) as exc:
        raise ValueError(f"Invalid quantity: {value}") from exc
    return max(quantity, 1)

