def _split_trailing_amount(line: str) -> tuple[str, Decimal] | None:
    match = TRAILING_AMOUNT.search(line)
    if not match:
        return None
    amount = _coerce_decimal(match.group("amount"))
    if amount is None or amount <= 0:
        return None
    left = line[: match.start()].strip()
    return left, amount

