def _classify_summary_label(left: str) -> str | None:
    normalized = re.sub(r"[^a-z]", "", left.lower())
    if not normalized:
        return None
    if "subtotal" in normalized or normalized in {"sub", "subttl"}:
        return "subtotal"
    if "tax" in normalized:
        return "tax"
    if "tip" in normalized or "gratuity" in normalized:
        return "tip"
    if (
        "total" in normalized
        or "amountdue" in normalized
        or "balancedue" in normalized
        or normalized.endswith("due")
    ):
        return "total"
    return None

