def _parse_item_from_line(left: str, amount: Decimal) -> CleanupReceiptItem | None:
    qty = 1
    name = left
    qty_match = LEADING_QTY.match(left)
    if qty_match:
        qty = int(qty_match.group("qty"))
        name = qty_match.group("rest").strip()

    cleaned_name = " ".join(name.split()).strip(" -:.")
    if not cleaned_name or _looks_like_non_item_text(cleaned_name):
        return None

    try:
        return CleanupReceiptItem(name=cleaned_name, price=amount, quantity=qty)
    except ValidationError:
        return None

