def _local_parse_is_sufficient(payload: CleanupReceiptPayload) -> bool:
    if not payload.items:
        return False

    items_sum = sum((item.price for item in payload.items), Decimal("0"))
    if len(payload.items) >= 2:
        return True
    if payload.subtotal is not None and abs(items_sum - payload.subtotal) <= MONEY_TOLERANCE:
        return True
    if payload.total is not None:
        expected = items_sum + (payload.tax or Decimal("0"))
        if abs(expected - payload.total) <= MONEY_TOLERANCE:
            return True
    return len(payload.items) == 1 and payload.items[0].price > 0

